<script setup lang="ts">
const route=useRoute();const schoolModules=useSchoolModules();await schoolModules.ready;const{modules}=schoolModules;const slugify=(value:string)=>value.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'');const categories=computed(()=>modules.value.informationCategories.filter(item=>item.status==='published'));const active=ref('');watch(categories,list=>{const match=list.find(item=>slugify(item.name)===String(route.params.jenis));if(!active.value)active.value=match?.id||list[0]?.id||''},{immediate:true});const items=computed(()=>modules.value.informationItems.filter(item=>item.status==='published'&&(!active.value||item.categoryId===active.value)).sort((a,b)=>new Date(b.date).getTime()-new Date(a.date).getTime()));const activeName=computed(()=>categories.value.find(item=>item.id===active.value)?.name||'Informasi');useSchoolSeo(activeName,()=>`Informasi ${activeName.value} SD Negeri Sukorame 2`)
</script>
<template><div><section class="bg-school-sky py-14"><div class="container-school"><p class="font-hand text-2xl font-bold text-school-action">Informasi Sekolah</p><h1 class="font-display mt-2 text-5xl text-school-navy">{{activeName}}</h1><div class="mt-6 flex flex-wrap gap-2"><button v-for="category in categories" :key="category.id" class="btn btn-secondary" :class="active===category.id?'ring-2 ring-school-action':''" @click="active=category.id">{{category.name}}</button></div></div></section><div class="container-school grid gap-6 py-12 md:grid-cols-2 lg:grid-cols-3"><article v-for="item in items" :key="item.id" class="card overflow-hidden"><div class="flex snap-x overflow-x-auto"><img v-for="(image,index) in item.images" :key="index" :src="image" :alt="item.title" class="aspect-[4/3] w-full shrink-0 snap-center object-cover"><img v-if="!item.images.length" src="https://cdn.sdnsukorame2kotakediri.sch.id/images/no-image.png" alt="Belum ada gambar" class="aspect-[4/3] w-full object-contain"></div><div class="p-5"><p class="text-xs text-muted">{{new Date(item.date).toLocaleDateString('id-ID',{dateStyle:'long'})}}</p><h2 class="mt-2 text-xl font-bold text-school-navy">{{item.title}}</h2><p class="mt-3 text-sm leading-6 text-muted">{{item.description}}</p></div></article><p v-if="!items.length" class="text-muted">Belum ada informasi terbit.</p></div></div></template>
